# Security configuration
MAX_QUERY_LENGTH = 1000
MAX_CONTEXT_LENGTH = 10000
ALLOWED_FILE_EXTENSIONS = {'.txt', '.md', '.pdf', '.docx'}
ALLOWED_DOCUMENTS = set()
SECRET_KEY = os.environ.get('SECRET_KEY')
