@dataclass
class SecureDocument:
    id: str
    content: str
    metadata: Dict[str, Any]

class SecureInputValidator:
    @staticmethod
    def validate_query(query: str) -> str:
        if not isinstance(query, str):
            raise ValueError("Query must be a string")
        if len(query) > MAX_QUERY_LENGTH:
            raise ValueError(f"Query exceeds maximum length of {MAX_QUERY_LENGTH}")
        return query.strip()
    
    @staticmethod
    def validate_document_path(path: str) -> str:
        if not isinstance(path, str):
            raise ValueError("Document path must be a string")
        if not path.startswith(DOCUMENTS_PATH):
            raise ValueError("Document path must be within allowed directory")
        return path

class SecureVectorStore:
    def __init__(self, vector_db_path: str):
        self.vector_db_path = vector_db_path
        self.embeddings = HuggingFaceEmbeddings(model_name="all-MiniLM-L6-v2")
        self.db = None
    
    def load_documents(self, document_paths: List[str]) -> None:
        documents = []
        for path in document_paths:
            try:
                path = SecureInputValidator.validate_document_path(path)
                if not os.path.exists(path):
                    logger.warning(f"Document not found: {path}")
                    continue
                
                with open(path, 'r', encoding='utf-8') as f:
                    content = f.read()
                
                doc = Document(
                    page_content=content,
                    metadata={"source": path}
                )
                documents.append(doc)
            except Exception as e:
                logger.error(f"Error loading document {path}: {e}")
                continue
        
        if not documents:
            raise ValueError("No valid documents loaded")
        
        text_splitter = RecursiveCharacterTextSplitter(
            chunk_size=1000,
            chunk_overlap=200
        )
        docs = text_splitter.split_documents(documents)
        
        self.db = Chroma.from_documents(
            docs,
            self.embeddings,
            persist_directory=self.vector_db_path
        )
        self.db.persist()
    
    def retrieve_context(self, query: str, k: int = 4) -> List[Dict[str, Any]]:
        if not self.db:
            raise ValueError("Vector store not initialized")
        
        results = self.db.similarity_search(query, k=k)
        return [
            {
                "content": doc.page_content,
                "metadata": doc.metadata
            }
            for doc in results
        ]

class SecureRetriever(BaseRetriever):
    def __init__(self, vector_store: SecureVectorStore):
        self.vector_store = vector_store
    
    def _get_relevant_documents(
        self, 
        query: str, 
        run_manager: CallbackManagerForRetrieverRun
    ) -> List[Document]:
        context = self.vector_store.retrieve_context(query)
        return [
            Document(
                page_content=doc["content"],
                metadata=doc["metadata"]
            )
            for doc in context
        ]

class SecureRAGSystem:
    def __init__(self):
        self.vector_store = SecureVectorStore(VECTOR_DB_PATH)
        self.retriever = None
        self.qa_chain = None
    
    def initialize(self, document_paths: List[str]):
        try:
            self.vector_store.load_documents(document_paths)
            self.retriever = SecureRetriever(self.vector_store)
            
            # Create secure prompt template
            template = """
            You are an internal knowledge base assistant. Use the following pieces of context to answer the question at the end.
            If you don't know the answer, just say you don't know, don't try to make up an answer.
            
            Context:
            {context}
            
            Question: {question}
            Answer:
            """
            
            prompt = PromptTemplate(
                template=template,
                input_variables=["context", "question"]
            )
            
            # Initialize LLM with security considerations
            llm = OpenAI(
                temperature=0,
                max_tokens=500,
                openai_api_key=OPENAI_API_KEY,
                model_name="text-davinci-003"
            )
            
            self.qa_chain = RetrievalQA.from_chain_type(
                llm=llm,
                chain_type="stuff",
                retriever=self.retriever,
                prompt=prompt,
                return_source_documents=True
            )
            
        except Exception as e:
            logger.error(f"Error initializing RAG system: {e}")
            raise
    
    def query(self, user_query: str) -> Dict[str, Any]:
        try:
            # Validate input
            query = SecureInputValidator.validate_query(user_query)
            
            if not self.qa_chain:
                raise ValueError("RAG system not initialized")
            
            # Execute query
            result = self.qa_chain({"query": query})
            
            # Sanitize output
            answer = result.get("result", "")
            source_documents = [
                {
                    "content": doc.page_content,
                    "metadata": doc.metadata
                }
                for doc in result.get("source_documents", [])
            ]
            
            return {
                "answer": answer,
                "source_documents": source_documents
            }
            
        except Exception as e:
            logger.error(f"Error processing query: {e}")
            raise

# Secure initialization function
def initialize_rag_system() -> SecureRAGSystem:
    # Load allowed documents from secure configuration
    allowed_docs = []
    try:
        for root, dirs, files in os.walk(DOCUMENTS_PATH):
            for file in files:
                if Path(file).suffix.lower() in ALLOWED_FILE_EXTENSIONS:
                    full_path = os.path.join(root, file)
                    allowed_docs.append(full_path)
    except Exception as e:
        logger.error(f"Error discovering documents: {e}")
        raise
    
    rag_system = SecureRAGSystem()
    rag_system.initialize(allowed_docs)
    return rag_system

